const subs = parseInt($input.first().json.statistics?.subscriberCount || 0);

const milestones = [100, 500, 1000, 2500, 5000, 10000, 25000, 50000, 100000];
const nextMilestone = milestones.find(m => m > subs) || 100000;
const prevMilestone = milestones.filter(m => m <= subs).pop() || 0;
const progress = prevMilestone > 0
  ? Math.round(((subs - prevMilestone) / (nextMilestone - prevMilestone)) * 100)
  : Math.round((subs / nextMilestone) * 100);

const remaining = nextMilestone - subs;

const isMilestone = milestones.includes(subs);

return [{ json: {
  subs: subs.toLocaleString(),
  subsRaw: subs,
  nextMilestone: nextMilestone.toLocaleString(),
  remaining: remaining.toLocaleString(),
  progress,
  isMilestone
}}];
